import { Component, Input, OnChanges, OnDestroy, OnInit, SimpleChanges, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Process } from '../../models/process.model';
import {
  FrameInfo,
  ProcessPageInfo,
  AddressTranslationStep,
  PagingConfig,
  ProcessSegmentInfo,
  SegmentEntry,
  MemoryBlock,
  SegmentAddressTranslationStep,
  PageReplacementResult,
  FragmentAnalysis,
  MemorySnapshot,
  SnapshotDiff,
} from '../../models/memory.model';
import { MemoryService } from '../../services/memory.service';

@Component({
  selector: 'app-memory-visualizer',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './memory-visualizer.component.html',
  styleUrls: ['./memory-visualizer.component.scss'],
})
export class MemoryVisualizerComponent implements OnInit, OnChanges, OnDestroy {
  @Input() processes: Process[] = [];
  @Input() completedProcessIds: number[] = [];

  isExpanded = true;
  activeTab: 'paging' | 'segmentation' = 'paging';

  totalMemoryKB = 256;
  pageSizeKB = 4;

  frames: FrameInfo[] = [];
  processPages: ProcessPageInfo[] = [];
  selectedProcessId: number | null = null;

  pageModalVisible = false;
  pageModalProcessId: number | null = null;
  pageModalPageCount = 1;

  translationLogicalAddress: number | null = null;
  translationSteps: AddressTranslationStep[] = [];

  memoryBlocks: MemoryBlock[] = [];
  processSegments: ProcessSegmentInfo[] = [];

  segmentModalVisible = false;
  segmentModalProcessId: number | null = null;
  segmentModalSegments: { segmentName: string; segmentLength: number }[] = [];
  newSegmentName = '';
  newSegmentLength = 4;

  segTranslationSegmentNumber: number | null = null;
  segTranslationOffset: number | null = null;
  segTranslationSteps: SegmentAddressTranslationStep[] = [];

  readonly memoryOptions = [64, 128, 256, 512, 1024];
  readonly pageSizeOptions = [1, 2, 4, 8];

  replacementFrameLimit = 3;
  replacementAccessSequence = '0,1,2,3,0,1,4,0,1,2,3,4';
  replacementAlgorithm: 'FIFO' | 'LRU' | 'OPT' = 'FIFO';
  replacementResult: PageReplacementResult | null = null;

  fragmentAnalysis: FragmentAnalysis | null = null;

  snapshots: MemorySnapshot[] = [];
  snapshotNameCounter = 1;
  selectedSnapshotIndex1: number | null = null;
  selectedSnapshotIndex2: number | null = null;
  snapshotDiff: SnapshotDiff | null = null;

  pendingReclaimPids: Set<number> = new Set();

  constructor(
    private memoryService: MemoryService,
    private cdr: ChangeDetectorRef
  ) {}

  ngOnInit(): void {
    this.initPagingIfNeeded();
    this.initSegmentationIfNeeded();
    if (this.selectedProcessId === null && this.processes.length > 0) {
      this.selectedProcessId = this.processes[0].id;
    }
  }

  ngOnDestroy(): void {}

  ngOnChanges(changes: SimpleChanges): void {
    if (changes['processes']) {
      this.syncProcesses();
    }
    if (changes['completedProcessIds']) {
      this.updatePendingReclaims();
    }
  }

  private updatePendingReclaims(): void {
    for (const pid of this.completedProcessIds) {
      if (!this.pendingReclaimPids.has(pid)) {
        const hasPages = this.processPages.some(p => p.processId === pid);
        const hasSegments = this.processSegments.some(p => p.processId === pid);
        if (hasPages || hasSegments) {
          this.pendingReclaimPids.add(pid);
        }
      }
    }
  }

  isProcessTerminated(processId: number): boolean {
    return this.completedProcessIds.includes(processId);
  }

  isProcessPendingReclaim(processId: number): boolean {
    return this.pendingReclaimPids.has(processId);
  }

  reclaimTerminatedProcesses(): void {
    for (const pid of this.pendingReclaimPids) {
      const pageResult = this.memoryService.releaseProcessPages(pid, this.frames, this.processPages);
      this.frames = pageResult.frames;
      this.processPages = pageResult.processPages;

      const segResult = this.memoryService.releaseProcessSegments(pid, this.memoryBlocks, this.processSegments);
      this.memoryBlocks = segResult.memoryBlocks;
      this.processSegments = segResult.processSegments;
    }
    this.pendingReclaimPids.clear();
  }

  get hasPendingReclaims(): boolean {
    return this.pendingReclaimPids.size > 0;
  }

  private syncProcesses(): void {
    const currentIds = this.processes.map((p) => p.id);

    const removedPagingIds = this.processPages
      .filter((pp) => !currentIds.includes(pp.processId))
      .map((pp) => pp.processId);
    for (const pid of removedPagingIds) {
      const result = this.memoryService.releaseProcessPages(pid, this.frames, this.processPages);
      this.frames = result.frames;
      this.processPages = result.processPages;
      this.pendingReclaimPids.delete(pid);
    }

    for (const pp of this.processPages) {
      const process = this.processes.find((p) => p.id === pp.processId);
      if (!process) {
        const result = this.memoryService.releaseProcessPages(pp.processId, this.frames, this.processPages);
        this.frames = result.frames;
        this.processPages = result.processPages;
      }
    }

    const removedSegIds = this.processSegments
      .filter((ps) => !currentIds.includes(ps.processId))
      .map((ps) => ps.processId);
    for (const pid of removedSegIds) {
      const result = this.memoryService.releaseProcessSegments(pid, this.memoryBlocks, this.processSegments);
      this.memoryBlocks = result.memoryBlocks;
      this.processSegments = result.processSegments;
      this.pendingReclaimPids.delete(pid);
    }

    if (this.selectedProcessId !== null && !currentIds.includes(this.selectedProcessId)) {
      this.selectedProcessId = this.processes.length > 0 ? this.processes[0].id : null;
    }

    if (this.selectedProcessId === null && this.processes.length > 0) {
      this.selectedProcessId = this.processes[0].id;
    }
  }

  get totalFrames(): number {
    return this.memoryService.getTotalFrames(this.pagingConfig);
  }

  get pagingConfig(): PagingConfig {
    return { totalMemoryKB: this.totalMemoryKB, pageSizeKB: this.pageSizeKB };
  }

  get freeFrameCount(): number {
    return this.frames.filter((f) => f.processId === null).length;
  }

  get selectedProcessPageInfo(): ProcessPageInfo | null {
    if (this.selectedProcessId === null) return null;
    return this.processPages.find((p) => p.processId === this.selectedProcessId) || null;
  }

  get selectedProcessSegmentInfo(): ProcessSegmentInfo | null {
    if (this.selectedProcessId === null) return null;
    return this.processSegments.find((p) => p.processId === this.selectedProcessId) || null;
  }

  toggleExpand(): void {
    this.isExpanded = !this.isExpanded;
  }

  onTotalMemoryChange(): void {
    this.resetPaging();
    this.resetSegmentation();
  }

  onPageSizeChange(): void {
    this.resetPaging();
  }

  resetPaging(): void {
    const total = this.totalFrames;
    this.frames = this.memoryService.initFrames(total);
    this.processPages = [];
    this.translationSteps = [];
    this.replacementResult = null;
  }

  resetSegmentation(): void {
    this.memoryBlocks = this.memoryService.initMemoryBlocks(this.totalMemoryKB);
    this.processSegments = [];
    this.segTranslationSteps = [];
    this.fragmentAnalysis = null;
  }

  getProcessById(id: number): Process | undefined {
    return this.processes.find((p) => p.id === id);
  }

  getProcessColor(id: number): string {
    return this.getProcessById(id)?.color || '#9ca3af';
  }

  openPageModal(processId: number): void {
    this.pageModalProcessId = processId;
    const existing = this.processPages.find((p) => p.processId === processId);
    this.pageModalPageCount = existing ? existing.logicalPageCount : 1;
    this.pageModalVisible = true;
  }

  closePageModal(): void {
    this.pageModalVisible = false;
    this.pageModalProcessId = null;
  }

  savePageModal(): void {
    if (this.pageModalProcessId === null) return;
    const pageCount = Math.max(1, Math.floor(this.pageModalPageCount));
    const maxPages = Math.floor(this.totalFrames / 2);
    if (pageCount > maxPages) {
      alert(`每个进程最多分配 ${maxPages} 页（总页框数的一半）`);
      return;
    }

    const existing = this.processPages.find((p) => p.processId === this.pageModalProcessId);
    if (existing) {
      const releaseResult = this.memoryService.releaseProcessPages(
        this.pageModalProcessId,
        this.frames,
        this.processPages
      );
      this.frames = releaseResult.frames;
      this.processPages = releaseResult.processPages;
    }

    const result = this.memoryService.allocatePages(
      this.pageModalProcessId,
      pageCount,
      this.frames,
      this.processPages,
      this.pagingConfig
    );

    if (!result) {
      alert('空闲页框不足，无法分配！');
      return;
    }

    this.frames = result.frames;
    this.processPages = result.processPages;
    this.closePageModal();
  }

  releaseProcessPages(processId: number): void {
    const result = this.memoryService.releaseProcessPages(processId, this.frames, this.processPages);
    this.frames = result.frames;
    this.processPages = result.processPages;
    this.pendingReclaimPids.delete(processId);
  }

  selectProcess(processId: number): void {
    this.selectedProcessId = processId;
  }

  translatePagingAddress(): void {
    if (this.translationLogicalAddress === null || this.selectedProcessId === null) return;
    const pInfo = this.processPages.find((p) => p.processId === this.selectedProcessId);
    if (!pInfo) {
      this.translationSteps = [{ label: '错误', value: '当前进程未分配页表', isError: true }];
      return;
    }
    this.translationSteps = this.memoryService.translatePagingAddress(
      this.translationLogicalAddress,
      pInfo,
      this.pageSizeKB
    );
  }

  openSegmentModal(processId: number): void {
    this.segmentModalProcessId = processId;
    const existing = this.processSegments.find((p) => p.processId === processId);
    if (existing) {
      this.segmentModalSegments = existing.segments.map((s) => ({
        segmentName: s.segmentName,
        segmentLength: s.segmentLength,
      }));
    } else {
      this.segmentModalSegments = [];
    }
    this.newSegmentName = '';
    this.newSegmentLength = 4;
    this.segmentModalVisible = true;
  }

  closeSegmentModal(): void {
    this.segmentModalVisible = false;
    this.segmentModalProcessId = null;
    this.segmentModalSegments = [];
  }

  addSegmentRow(): void {
    if (this.segmentModalSegments.length >= 8) return;
    this.segmentModalSegments.push({
      segmentName: this.newSegmentName.trim() || `段${this.segmentModalSegments.length}`,
      segmentLength: Math.max(1, Math.min(128, this.newSegmentLength)),
    });
    this.newSegmentName = '';
    this.newSegmentLength = 4;
  }

  removeSegmentRow(index: number): void {
    this.segmentModalSegments.splice(index, 1);
  }

  saveSegmentModal(): void {
    if (this.segmentModalProcessId === null) return;
    if (this.segmentModalSegments.length === 0) {
      alert('请至少添加一个段');
      return;
    }

    const existing = this.processSegments.find((p) => p.processId === this.segmentModalProcessId);
    if (existing) {
      const releaseResult = this.memoryService.releaseProcessSegments(
        this.segmentModalProcessId,
        this.memoryBlocks,
        this.processSegments
      );
      this.memoryBlocks = releaseResult.memoryBlocks;
      this.processSegments = releaseResult.processSegments;
    }

    const result = this.memoryService.allocateSegments(
      this.segmentModalProcessId,
      this.segmentModalSegments,
      this.memoryBlocks,
      this.processSegments,
      this.totalMemoryKB
    );

    if (!result) {
      alert('内存空间不足，无法为所有段分配空间！');
      return;
    }

    this.memoryBlocks = result.memoryBlocks;
    this.processSegments = result.processSegments;
    this.closeSegmentModal();
  }

  releaseProcessSegments(processId: number): void {
    const result = this.memoryService.releaseProcessSegments(processId, this.memoryBlocks, this.processSegments);
    this.memoryBlocks = result.memoryBlocks;
    this.processSegments = result.processSegments;
    this.pendingReclaimPids.delete(processId);
  }

  translateSegmentAddress(): void {
    if (this.segTranslationSegmentNumber === null || this.segTranslationOffset === null || this.selectedProcessId === null) return;
    const sInfo = this.processSegments.find((p) => p.processId === this.selectedProcessId);
    if (!sInfo) {
      this.segTranslationSteps = [{ label: '错误', value: '当前进程未配置段表', isError: true }];
      return;
    }
    this.segTranslationSteps = this.memoryService.translateSegmentAddress(
      Math.floor(this.segTranslationSegmentNumber),
      Math.floor(this.segTranslationOffset),
      sInfo
    );
  }

  getFrameTooltip(frame: FrameInfo): string {
    if (frame.processId === null) return `页框 ${frame.frameNumber}: 空闲`;
    const proc = this.getProcessById(frame.processId);
    return `页框 ${frame.frameNumber}: ${proc?.name || 'P' + frame.processId} 页${frame.logicalPage}`;
  }

  getFrameLabel(frame: FrameInfo): string {
    if (frame.processId === null) return '';
    const proc = this.getProcessById(frame.processId);
    return `${proc?.name || 'P' + frame.processId}:${frame.logicalPage}`;
  }

  getBlockTooltip(block: MemoryBlock): string {
    if (block.isFree) return `空闲区: ${block.startAddress}-${block.startAddress + block.size - 1} (${block.size}KB)`;
    const proc = this.getProcessById(block.processId!);
    return `${proc?.name || 'P' + block.processId} ${block.segmentName}: ${block.startAddress}-${block.startAddress + block.size - 1} (${block.size}KB)`;
  }

  getBlockWidthPercent(block: MemoryBlock): number {
    return (block.size / this.totalMemoryKB) * 100;
  }

  getProcessHasPages(processId: number): boolean {
    return this.processPages.some((p) => p.processId === processId);
  }

  getProcessHasSegments(processId: number): boolean {
    return this.processSegments.some((p) => p.processId === processId);
  }

  stopPropagation(event: Event): void {
    event.stopPropagation();
  }

  getMaxPageCount(): number {
    return Math.floor(this.totalFrames / 2);
  }

  getSegmentTableRows(): { segNumber: number; segName: string; base: number; length: number }[] {
    const info = this.selectedProcessSegmentInfo;
    if (!info) return [];
    return info.segments.map((s, i) => ({
      segNumber: i,
      segName: s.segmentName,
      base: s.baseAddress,
      length: s.segmentLength,
    }));
  }

  initPagingIfNeeded(): void {
    if (this.frames.length === 0 || this.frames.length !== this.totalFrames) {
      this.resetPaging();
    }
  }

  initSegmentationIfNeeded(): void {
    if (this.memoryBlocks.length === 0) {
      this.resetSegmentation();
    }
  }

  onTabChange(tab: 'paging' | 'segmentation'): void {
    this.activeTab = tab;
    if (tab === 'paging') {
      this.initPagingIfNeeded();
    } else {
      this.initSegmentationIfNeeded();
    }
  }

  getSelectedProcessName(): string {
    if (this.selectedProcessId === null) return '未选择';
    const proc = this.getProcessById(this.selectedProcessId);
    return proc ? proc.name : '未选择';
  }

  getBlockBgColor(block: MemoryBlock): string {
    if (block.isFree) return 'transparent';
    return this.getProcessColor(block.processId!) + 'cc';
  }

  getBlockLabel(block: MemoryBlock): string {
    if (block.isFree) return '';
    const proc = this.getProcessById(block.processId!);
    return (proc ? proc.name : 'P' + block.processId) + ':' + block.segmentName;
  }

  getProcessPageCount(processId: number): number {
    const info = this.processPages.find((p) => p.processId === processId);
    return info ? info.logicalPageCount : 0;
  }

  getProcessSegmentCount(processId: number): number {
    const info = this.processSegments.find((p) => p.processId === processId);
    return info ? info.segments.length : 0;
  }

  getReplacementMaxFrameLimit(): number {
    const pInfo = this.processPages.find(p => p.processId === this.selectedProcessId);
    if (!pInfo) return 2;
    return Math.max(2, pInfo.logicalPageCount);
  }

  getReplacementMinFrameLimit(): number {
    return 2;
  }

  startReplacementSimulation(): void {
    const sequence = this.replacementAccessSequence
      .split(',')
      .map(s => s.trim())
      .filter(s => s !== '')
      .map(s => parseInt(s, 10))
      .filter(n => !isNaN(n));

    if (sequence.length === 0) {
      alert('请输入有效的页面访问序列');
      return;
    }

    const pInfo = this.processPages.find(p => p.processId === this.selectedProcessId);
    if (!pInfo) {
      alert('请先为当前进程分配页表');
      return;
    }

    const totalPages = pInfo.logicalPageCount;
    const frameLimit = Math.max(2, Math.min(this.replacementFrameLimit, totalPages));

    switch (this.replacementAlgorithm) {
      case 'FIFO':
        this.replacementResult = this.memoryService.simulateFIFO(sequence, frameLimit, totalPages);
        break;
      case 'LRU':
        this.replacementResult = this.memoryService.simulateLRU(sequence, frameLimit, totalPages);
        break;
      case 'OPT':
        this.replacementResult = this.memoryService.simulateOPT(sequence, frameLimit, totalPages);
        break;
    }
  }

  analyzeFragments(): void {
    this.fragmentAnalysis = this.memoryService.analyzeFragments(this.memoryBlocks);
  }

  canCompact(): boolean {
    if (!this.fragmentAnalysis) return false;
    return this.fragmentAnalysis.freeBlockCount > 1;
  }

  executeCompaction(): void {
    const result = this.memoryService.compactMemory(this.memoryBlocks, this.processSegments);
    this.memoryBlocks = result.memoryBlocks;
    this.processSegments = result.processSegments;
    this.fragmentAnalysis = this.memoryService.analyzeFragments(this.memoryBlocks);
  }

  saveSnapshot(): void {
    if (this.snapshots.length >= 5) {
      alert('快照已满（最多5个），请先删除旧快照');
      return;
    }

    const snapshot: MemorySnapshot = {
      name: `快照${this.snapshotNameCounter}`,
      timestamp: new Date(),
      frames: this.frames.map(f => ({ ...f })),
      processPages: this.processPages.map(pp => ({
        processId: pp.processId,
        logicalPageCount: pp.logicalPageCount,
        pageTable: pp.pageTable.map(e => ({ ...e })),
      })),
      memoryBlocks: this.memoryBlocks.map(b => ({ ...b })),
      processSegments: this.processSegments.map(ps => ({
        processId: ps.processId,
        segments: ps.segments.map(s => ({ ...s })),
      })),
      totalMemoryKB: this.totalMemoryKB,
      pageSizeKB: this.pageSizeKB,
    };

    this.snapshots.push(snapshot);
    this.snapshotNameCounter++;
  }

  restoreSnapshot(index: number): void {
    const snapshot = this.snapshots[index];
    if (!snapshot) return;

    this.totalMemoryKB = snapshot.totalMemoryKB;
    this.pageSizeKB = snapshot.pageSizeKB;

    const newFrames = snapshot.frames.map(f => ({ ...f }));
    const newProcessPages = snapshot.processPages.map(pp => ({
      processId: pp.processId,
      logicalPageCount: pp.logicalPageCount,
      pageTable: pp.pageTable.map(e => ({ ...e })),
    }));
    const newMemoryBlocks = snapshot.memoryBlocks.map(b => ({ ...b }));
    const newProcessSegments = snapshot.processSegments.map(ps => ({
      processId: ps.processId,
      segments: ps.segments.map(s => ({ ...s })),
    }));

    this.frames = [];
    this.processPages = [];
    this.memoryBlocks = [];
    this.processSegments = [];
    this.pendingReclaimPids.clear();

    setTimeout(() => {
      this.frames = newFrames;
      this.processPages = newProcessPages;
      this.memoryBlocks = newMemoryBlocks;
      this.processSegments = newProcessSegments;

      this.translationSteps = [];
      this.segTranslationSteps = [];
      this.replacementResult = null;
      this.fragmentAnalysis = null;

      if (this.selectedProcessId !== null) {
        const pidsInPaging = this.processPages.map(p => p.processId);
        const pidsInSeg = this.processSegments.map(p => p.processId);
        if (!pidsInPaging.includes(this.selectedProcessId) && !pidsInSeg.includes(this.selectedProcessId)) {
          this.selectedProcessId = this.processes.length > 0 ? this.processes[0].id : null;
        }
      }

      this.cdr.detectChanges();
    }, 0);
  }

  deleteSnapshot(index: number): void {
    this.snapshots.splice(index, 1);
    if (this.selectedSnapshotIndex1 !== null && this.selectedSnapshotIndex1 >= this.snapshots.length) {
      this.selectedSnapshotIndex1 = null;
    }
    if (this.selectedSnapshotIndex2 !== null && this.selectedSnapshotIndex2 >= this.snapshots.length) {
      this.selectedSnapshotIndex2 = null;
    }
    this.snapshotDiff = null;
  }

  toggleSnapshotSelection(index: number): void {
    if (this.selectedSnapshotIndex1 === index) {
      this.selectedSnapshotIndex1 = null;
      this.snapshotDiff = null;
      return;
    }
    if (this.selectedSnapshotIndex2 === index) {
      this.selectedSnapshotIndex2 = null;
      this.snapshotDiff = null;
      return;
    }
    if (this.selectedSnapshotIndex1 === null) {
      this.selectedSnapshotIndex1 = index;
    } else if (this.selectedSnapshotIndex2 === null) {
      this.selectedSnapshotIndex2 = index;
    } else {
      this.selectedSnapshotIndex1 = index;
      this.selectedSnapshotIndex2 = null;
      this.snapshotDiff = null;
    }
  }

  compareSelectedSnapshots(): void {
    if (this.selectedSnapshotIndex1 === null || this.selectedSnapshotIndex2 === null) return;
    const s1 = this.snapshots[this.selectedSnapshotIndex1];
    const s2 = this.snapshots[this.selectedSnapshotIndex2];
    if (!s1 || !s2) return;

    this.snapshotDiff = this.memoryService.compareSnapshots(
      s1.frames, s1.processPages, s1.memoryBlocks, s1.processSegments,
      s2.frames, s2.processPages, s2.memoryBlocks, s2.processSegments
    );
  }

  isSnapshotSelected(index: number): boolean {
    return this.selectedSnapshotIndex1 === index || this.selectedSnapshotIndex2 === index;
  }

  getProcessNameById(pid: number): string {
    const proc = this.getProcessById(pid);
    return proc ? proc.name : `P${pid}`;
  }

  isFramePendingReclaim(frame: FrameInfo): boolean {
    return frame.processId !== null && this.pendingReclaimPids.has(frame.processId);
  }

  isBlockPendingReclaim(block: MemoryBlock): boolean {
    return block.processId !== null && this.pendingReclaimPids.has(block.processId);
  }

  formatTimestamp(date: Date): string {
    const d = new Date(date);
    const h = d.getHours().toString().padStart(2, '0');
    const m = d.getMinutes().toString().padStart(2, '0');
    const s = d.getSeconds().toString().padStart(2, '0');
    return `${h}:${m}:${s}`;
  }

  trackByFrameNumber(index: number, frame: FrameInfo): number {
    return frame.frameNumber;
  }

  trackByBlockAddress(index: number, block: MemoryBlock): number {
    return block.startAddress;
  }

  trackBySnapshotName(index: number, snapshot: MemorySnapshot): string {
    return snapshot.name;
  }
}
<div class="memory-visualizer">
  <div class="section-header" (click)="toggleExpand()">
    <div class="header-content">
      <span class="toggle-icon">{{ isExpanded ? '▼' : '▶' }}</span>
      <h2 class="section-title">🧠 内存管理可视化</h2>
      <span class="subtitle">分页式 · 分段式 · 地址转换</span>
    </div>
  </div>

  <div class="section-body" *ngIf="isExpanded">
    <div class="tab-bar">
      <div class="tab-buttons">
        <button
          class="tab-btn"
          [class.active]="activeTab === 'paging'"
          (click)="onTabChange('paging')"
        >
          📄 分页式内存管理
        </button>
        <button
          class="tab-btn"
          [class.active]="activeTab === 'segmentation'"
          (click)="onTabChange('segmentation')"
        >
          📦 分段式内存管理
        </button>
      </div>
      <div class="tab-actions">
        <button class="btn btn-snapshot" (click)="saveSnapshot()" title="保存当前内存状态快照">
          📸 保存快照
        </button>
        <button
          *ngIf="hasPendingReclaims"
          class="btn btn-reclaim"
          (click)="reclaimTerminatedProcesses()"
          title="回收已结束进程占用的内存"
        >
          ♻️ 回收已结束进程内存
        </button>
      </div>
    </div>

    <ng-container *ngIf="activeTab === 'paging'">
      <div class="config-section card">
        <div class="card-title">⚙️ 分页配置</div>
        <div class="config-row">
          <div class="config-item">
            <label>物理内存总大小</label>
            <select [(ngModel)]="totalMemoryKB" (ngModelChange)="onTotalMemoryChange()" class="form-select">
              <option *ngFor="let opt of memoryOptions" [ngValue]="opt">{{ opt }}KB</option>
            </select>
          </div>
          <div class="config-item">
            <label>页面大小</label>
            <select [(ngModel)]="pageSizeKB" (ngModelChange)="onPageSizeChange()" class="form-select">
              <option *ngFor="let opt of pageSizeOptions" [ngValue]="opt">{{ opt }}KB</option>
            </select>
          </div>
          <div class="config-item">
            <label>总页框数</label>
            <span class="info-value">{{ totalFrames }}</span>
          </div>
          <div class="config-item">
            <label>空闲页框</label>
            <span class="info-value" [class.warning]="freeFrameCount === 0">{{ freeFrameCount }}</span>
          </div>
        </div>
      </div>

      <div class="process-list-section card">
        <div class="card-title">📋 进程页表配置</div>
        <div *ngIf="processes.length === 0" class="empty-state">暂无进程</div>
        <table *ngIf="processes.length > 0" class="process-table">
          <thead>
            <tr>
              <th>进程</th>
              <th>状态</th>
              <th>已分配页数</th>
              <th>操作</th>
            </tr>
          </thead>
          <tbody>
            <tr
              *ngFor="let proc of processes"
              [class.selected]="selectedProcessId === proc.id"
              [class.terminated-row]="isProcessTerminated(proc.id)"
              [class.pending-reclaim-row]="isProcessPendingReclaim(proc.id)"
              (click)="selectProcess(proc.id)"
            >
              <td>
                <span class="process-badge" [style.backgroundColor]="proc.color">
                  {{ proc.name }}
                </span>
              </td>
              <td>
                <span *ngIf="isProcessPendingReclaim(proc.id)" class="status-badge status-pending-reclaim" title="待回收">待回收</span>
                <span *ngIf="!isProcessPendingReclaim(proc.id) && isProcessTerminated(proc.id)" class="status-badge status-terminated" title="已结束">已结束</span>
                <span *ngIf="!isProcessPendingReclaim(proc.id) && !isProcessTerminated(proc.id)" class="status-badge status-active">运行中</span>
              </td>
              <td>
                <ng-container *ngIf="getProcessHasPages(proc.id); else noPages">
                  {{ getProcessPageCount(proc.id) }} 页
                </ng-container>
                <ng-template #noPages>
                  <span class="text-muted">未分配</span>
                </ng-template>
              </td>
              <td>
                <button class="btn btn-small btn-secondary" (click)="openPageModal(proc.id)">
                  页表
                </button>
                <button
                  *ngIf="getProcessHasPages(proc.id)"
                  class="btn btn-small btn-delete"
                  (click)="releaseProcessPages(proc.id)"
                >
                  释放
                </button>
              </td>
            </tr>
          </tbody>
        </table>
      </div>

      <div class="visualization-grid">
        <div class="card">
          <div class="card-title">🗂️ 物理内存页框图</div>
          <div class="frames-grid" *ngIf="frames.length > 0">
            <div
              *ngFor="let frame of frames; trackBy: trackByFrameNumber"
              class="frame-block"
              [class.free]="frame.processId === null"
              [class.allocated]="frame.processId !== null"
              [class.pending-reclaim-frame]="isFramePendingReclaim(frame)"
              [style.backgroundColor]="frame.processId !== null ? getProcessColor(frame.processId) + 'cc' : '#e5e7eb'"
              [title]="getFrameTooltip(frame)"
            >
              <div class="frame-number">{{ frame.frameNumber }}</div>
              <div *ngIf="frame.processId !== null" class="frame-label">
                {{ getFrameLabel(frame) }}
              </div>
            </div>
          </div>
          <div class="frames-legend">
            <span class="legend-item">
              <span class="legend-color free-color"></span> 空闲
            </span>
            <span class="legend-item">
              <span class="legend-color allocated-color"></span> 已分配
            </span>
            <span class="legend-item" *ngIf="hasPendingReclaims">
              <span class="legend-color reclaim-color"></span> 待回收
            </span>
          </div>
        </div>

        <div class="card">
          <div class="card-title">📖 页表 - {{ getSelectedProcessName() }}</div>
          <div *ngIf="!selectedProcessPageInfo" class="empty-state">
            请选择一个已分配页表的进程
          </div>
          <table *ngIf="selectedProcessPageInfo" class="page-table">
            <thead>
              <tr>
                <th>逻辑页号</th>
                <th>物理页框号</th>
              </tr>
            </thead>
            <tbody>
              <tr *ngFor="let entry of selectedProcessPageInfo.pageTable">
                <td>{{ entry.logicalPage }}</td>
                <td>{{ entry.physicalFrame }}</td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>

      <div class="card">
        <div class="card-title">🔍 地址转换演示 (分页)</div>
        <div class="translation-form">
          <div class="form-row-inline">
            <label>逻辑地址 (十进制):</label>
            <input
              type="number"
              min="0"
              [(ngModel)]="translationLogicalAddress"
              class="form-input addr-input"
              placeholder="输入逻辑地址"
            />
            <button
              class="btn btn-primary"
              (click)="translatePagingAddress()"
              [disabled]="translationLogicalAddress === null || !selectedProcessPageInfo"
            >
              转换
            </button>
          </div>
        </div>
        <div *ngIf="translationSteps.length > 0" class="translation-steps">
          <div
            *ngFor="let step of translationSteps"
            class="step-row"
            [class.error-step]="step.isError"
          >
            <span class="step-label">{{ step.label }}</span>
            <span class="step-value">{{ step.value }}</span>
          </div>
        </div>
      </div>

      <div class="card">
        <div class="card-title">🔄 页面置换模拟</div>
        <div class="replacement-config">
          <div class="form-row-inline">
            <label>物理页框上限:</label>
            <input
              type="number"
              [min]="getReplacementMinFrameLimit()"
              [max]="getReplacementMaxFrameLimit()"
              [(ngModel)]="replacementFrameLimit"
              class="form-input small-input"
            />
            <label>访问序列 (逗号分隔):</label>
            <input
              type="text"
              [(ngModel)]="replacementAccessSequence"
              class="form-input seq-input"
              placeholder="如: 0,1,2,3,0,1,4,0,1,2,3,4"
            />
          </div>
          <div class="form-row-inline">
            <label>置换算法:</label>
            <select [(ngModel)]="replacementAlgorithm" class="form-select">
              <option value="FIFO">FIFO</option>
              <option value="LRU">LRU</option>
              <option value="OPT">OPT (最优)</option>
            </select>
            <button
              class="btn btn-primary"
              (click)="startReplacementSimulation()"
              [disabled]="!selectedProcessPageInfo"
            >
              开始模拟
            </button>
          </div>
        </div>

        <div *ngIf="replacementResult" class="replacement-result">
          <div class="replacement-summary">
            <span class="summary-item">算法: <strong>{{ replacementResult.algorithm }}</strong></span>
            <span class="summary-item">缺页次数: <strong [class.fault-highlight]="true">{{ replacementResult.faultCount }}</strong></span>
            <span class="summary-item">缺页率: <strong [class.fault-highlight]="replacementResult.faultRate > 0.5">{{ (replacementResult.faultRate * 100).toFixed(1) }}%</strong></span>
          </div>
          <div class="replacement-table-wrapper">
            <table class="replacement-table">
              <thead>
                <tr>
                  <th>步骤</th>
                  <th>访问页号</th>
                  <th>页框内容</th>
                  <th>命中/缺页</th>
                  <th>换出页号</th>
                </tr>
              </thead>
              <tbody>
                <tr *ngFor="let step of replacementResult.steps; let i = index"
                    [class.hit-row]="step.hit"
                    [class.miss-row]="!step.hit">
                  <td>{{ i + 1 }}</td>
                  <td>{{ step.accessPage }}</td>
                  <td class="mono">{{ step.framesContent.join(', ') }}</td>
                  <td>
                    <span *ngIf="step.hit" class="hit-badge">命中</span>
                    <span *ngIf="!step.hit" class="miss-badge">缺页</span>
                  </td>
                  <td>{{ step.evictedPage !== null ? step.evictedPage : '-' }}</td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </ng-container>

    <ng-container *ngIf="activeTab === 'segmentation'">
      <div class="config-section card">
        <div class="card-title">⚙️ 分段配置</div>
        <div class="config-row">
          <div class="config-item">
            <label>物理内存总大小</label>
            <select [(ngModel)]="totalMemoryKB" (ngModelChange)="onTotalMemoryChange()" class="form-select">
              <option *ngFor="let opt of memoryOptions" [ngValue]="opt">{{ opt }}KB</option>
            </select>
          </div>
        </div>
      </div>

      <div class="process-list-section card">
        <div class="card-title">📋 进程段配置</div>
        <div *ngIf="processes.length === 0" class="empty-state">暂无进程</div>
        <table *ngIf="processes.length > 0" class="process-table">
          <thead>
            <tr>
              <th>进程</th>
              <th>状态</th>
              <th>段数</th>
              <th>操作</th>
            </tr>
          </thead>
          <tbody>
            <tr
              *ngFor="let proc of processes"
              [class.selected]="selectedProcessId === proc.id"
              [class.terminated-row]="isProcessTerminated(proc.id)"
              [class.pending-reclaim-row]="isProcessPendingReclaim(proc.id)"
              (click)="selectProcess(proc.id)"
            >
              <td>
                <span class="process-badge" [style.backgroundColor]="proc.color">
                  {{ proc.name }}
                </span>
              </td>
              <td>
                <span *ngIf="isProcessPendingReclaim(proc.id)" class="status-badge status-pending-reclaim">待回收</span>
                <span *ngIf="!isProcessPendingReclaim(proc.id) && isProcessTerminated(proc.id)" class="status-badge status-terminated">已结束</span>
                <span *ngIf="!isProcessPendingReclaim(proc.id) && !isProcessTerminated(proc.id)" class="status-badge status-active">运行中</span>
              </td>
              <td>
                <ng-container *ngIf="getProcessHasSegments(proc.id); else noSegs">
                  {{ getProcessSegmentCount(proc.id) }} 段
                </ng-container>
                <ng-template #noSegs>
                  <span class="text-muted">未分配</span>
                </ng-template>
              </td>
              <td>
                <button class="btn btn-small btn-secondary" (click)="openSegmentModal(proc.id)">
                  配置段
                </button>
                <button
                  *ngIf="getProcessHasSegments(proc.id)"
                  class="btn btn-small btn-delete"
                  (click)="releaseProcessSegments(proc.id)"
                >
                  释放
                </button>
              </td>
            </tr>
          </tbody>
        </table>
      </div>

      <div class="visualization-grid">
        <div class="card">
          <div class="card-title">📊 物理内存条形图</div>
          <div class="memory-bar-container">
            <div class="memory-bar">
              <div
                *ngFor="let block of memoryBlocks; trackBy: trackByBlockAddress"
                class="memory-block"
                [class.free-block]="block.isFree"
                [class.allocated-block]="!block.isFree"
                [class.pending-reclaim-block]="isBlockPendingReclaim(block)"
                [style.width]="getBlockWidthPercent(block) + '%'"
                [style.backgroundColor]="getBlockBgColor(block)"
                [title]="getBlockTooltip(block)"
              >
                <div *ngIf="!block.isFree && getBlockWidthPercent(block) > 8" class="block-label">
                  {{ getBlockLabel(block) }}
                </div>
                <div *ngIf="block.isFree && getBlockWidthPercent(block) > 5" class="block-label free-label">
                  空闲({{ block.size }}KB)
                </div>
              </div>
            </div>
            <div class="memory-address-bar">
              <span>0</span>
              <span>{{ totalMemoryKB }}KB</span>
            </div>
          </div>
        </div>

        <div class="card">
          <div class="card-title">📖 段表 - {{ getSelectedProcessName() }}</div>
          <div *ngIf="!selectedProcessSegmentInfo" class="empty-state">
            请选择一个已配置段的进程
          </div>
          <table *ngIf="selectedProcessSegmentInfo" class="segment-table">
            <thead>
              <tr>
                <th>段号</th>
                <th>段名</th>
                <th>基址</th>
                <th>段长</th>
              </tr>
            </thead>
            <tbody>
              <tr *ngFor="let row of getSegmentTableRows()">
                <td>{{ row.segNumber }}</td>
                <td>{{ row.segName }}</td>
                <td>{{ row.base }}</td>
                <td>{{ row.length }}KB</td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>

      <div class="card">
        <div class="card-title">🔍 地址转换演示 (分段)</div>
        <div class="translation-form">
          <div class="form-row-inline">
            <label>段号:</label>
            <input
              type="number"
              min="0"
              [(ngModel)]="segTranslationSegmentNumber"
              class="form-input addr-input"
              placeholder="段号"
            />
            <label>段内偏移 (KB):</label>
            <input
              type="number"
              min="0"
              [(ngModel)]="segTranslationOffset"
              class="form-input addr-input"
              placeholder="偏移"
            />
            <button
              class="btn btn-primary"
              (click)="translateSegmentAddress()"
              [disabled]="segTranslationSegmentNumber === null || segTranslationOffset === null || !selectedProcessSegmentInfo"
            >
              转换
            </button>
          </div>
        </div>
        <div *ngIf="segTranslationSteps.length > 0" class="translation-steps">
          <div
            *ngFor="let step of segTranslationSteps"
            class="step-row"
            [class.error-step]="step.isError"
          >
            <span class="step-label">{{ step.label }}</span>
            <span class="step-value">{{ step.value }}</span>
          </div>
        </div>
      </div>

      <div class="card">
        <div class="card-title">🔧 碎片分析</div>
        <div class="fragment-actions">
          <button class="btn btn-primary" (click)="analyzeFragments()">分析碎片</button>
          <button
            *ngIf="canCompact()"
            class="btn btn-warning"
            (click)="executeCompaction()"
          >
            执行紧凑
          </button>
        </div>
        <div *ngIf="fragmentAnalysis" class="fragment-result">
          <div class="fragment-stats">
            <div class="stat-item">
              <span class="stat-label">外部碎片总量</span>
              <span class="stat-value">{{ fragmentAnalysis.totalFragmentSize }} KB</span>
            </div>
            <div class="stat-item">
              <span class="stat-label">空闲区块数</span>
              <span class="stat-value">{{ fragmentAnalysis.freeBlockCount }}</span>
            </div>
            <div class="stat-item">
              <span class="stat-label">最大空闲块</span>
              <span class="stat-value">{{ fragmentAnalysis.maxFreeBlockSize }} KB</span>
            </div>
            <div class="stat-item">
              <span class="stat-label">碎片率</span>
              <span class="stat-value" [class.fault-highlight]="fragmentAnalysis.fragmentationRate > 0.5">
                {{ (fragmentAnalysis.fragmentationRate * 100).toFixed(1) }}%
              </span>
            </div>
          </div>
          <div *ngIf="fragmentAnalysis.freeBlockCount <= 1" class="compact-hint">
            ✅ 碎片已合并，无需紧凑
          </div>
        </div>
        <div *ngIf="!fragmentAnalysis" class="empty-state">
          点击"分析碎片"查看碎片状况
        </div>
      </div>
    </ng-container>

    <div class="card" *ngIf="snapshots.length > 0 || true">
      <div class="card-title">📸 内存快照</div>
      <div *ngIf="snapshots.length === 0" class="empty-state">
        点击顶部"保存快照"按钮保存当前内存状态
      </div>
      <div *ngIf="snapshots.length > 0" class="snapshot-list">
        <div
          *ngFor="let snap of snapshots; let i = index; trackBy: trackBySnapshotName"
          class="snapshot-item"
          [class.selected]="isSnapshotSelected(i)"
          (click)="toggleSnapshotSelection(i)"
        >
          <div class="snapshot-info">
            <span class="snapshot-name">{{ snap.name }}</span>
            <span class="snapshot-time">{{ formatTimestamp(snap.timestamp) }}</span>
          </div>
          <div class="snapshot-actions">
            <button class="btn btn-small btn-secondary" (click)="restoreSnapshot(i); $event.stopPropagation()">
              恢复
            </button>
            <button class="btn btn-small btn-delete" (click)="deleteSnapshot(i); $event.stopPropagation()">
              删除
            </button>
          </div>
        </div>
      </div>
      <div *ngIf="snapshots.length > 0" class="snapshot-compare">
        <button
          class="btn btn-primary"
          (click)="compareSelectedSnapshots()"
          [disabled]="selectedSnapshotIndex1 === null || selectedSnapshotIndex2 === null"
        >
          对比选中快照
        </button>
        <span *ngIf="selectedSnapshotIndex1 !== null && selectedSnapshotIndex2 === null" class="compare-hint">
          请再选择一个快照进行对比
        </span>
      </div>

      <div *ngIf="snapshotDiff" class="snapshot-diff-result">
        <div class="card-title">📊 快照对比结果</div>
        <table class="diff-table">
          <thead>
            <tr>
              <th>对比项</th>
              <th>详情</th>
            </tr>
          </thead>
          <tbody>
            <tr>
              <td>分页变化的进程</td>
              <td>
                <ng-container *ngIf="snapshotDiff.pagingChangedProcessIds.length === 0">无变化</ng-container>
                <span *ngFor="let pid of snapshotDiff.pagingChangedProcessIds" class="diff-badge">
                  {{ getProcessNameById(pid) }}
                </span>
              </td>
            </tr>
            <tr>
              <td>分段变化的进程</td>
              <td>
                <ng-container *ngIf="snapshotDiff.segmentationChangedProcessIds.length === 0">无变化</ng-container>
                <span *ngFor="let pid of snapshotDiff.segmentationChangedProcessIds" class="diff-badge">
                  {{ getProcessNameById(pid) }}
                </span>
              </td>
            </tr>
            <tr>
              <td>页框占用差异</td>
              <td>
                <span *ngIf="snapshotDiff.frameOccupancyDiff > 0" class="diff-increase">+{{ snapshotDiff.frameOccupancyDiff }}</span>
                <span *ngIf="snapshotDiff.frameOccupancyDiff < 0" class="diff-decrease">{{ snapshotDiff.frameOccupancyDiff }}</span>
                <span *ngIf="snapshotDiff.frameOccupancyDiff === 0">无变化</span>
              </td>
            </tr>
            <tr>
              <td>空闲内存变化</td>
              <td>
                <span *ngIf="snapshotDiff.freeMemoryDiff > 0" class="diff-increase">+{{ snapshotDiff.freeMemoryDiff }} KB</span>
                <span *ngIf="snapshotDiff.freeMemoryDiff < 0" class="diff-decrease">{{ snapshotDiff.freeMemoryDiff }} KB</span>
                <span *ngIf="snapshotDiff.freeMemoryDiff === 0">无变化</span>
              </td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>
  </div>

  <div class="modal-overlay" *ngIf="pageModalVisible" (click)="closePageModal()">
    <div class="modal-content" (click)="stopPropagation($event)">
      <div class="modal-header">
        <h3>配置页表 - {{ getProcessById(pageModalProcessId!)?.name }}</h3>
        <button class="close-btn" (click)="closePageModal()">✕</button>
      </div>
      <div class="modal-body">
        <div class="form-section">
          <h4>逻辑页数</h4>
          <p class="form-hint">最大可分配 {{ getMaxPageCount() }} 页（总页框数的一半）</p>
          <input
            type="number"
            min="1"
            [max]="getMaxPageCount()"
            [(ngModel)]="pageModalPageCount"
            class="form-input"
          />
        </div>
      </div>
      <div class="modal-footer">
        <button class="btn btn-secondary" (click)="closePageModal()">取消</button>
        <button class="btn btn-primary" (click)="savePageModal()">分配</button>
      </div>
    </div>
  </div>

  <div class="modal-overlay" *ngIf="segmentModalVisible" (click)="closeSegmentModal()">
    <div class="modal-content modal-wide" (click)="stopPropagation($event)">
      <div class="modal-header">
        <h3>配置段 - {{ getProcessById(segmentModalProcessId!)?.name }}</h3>
        <button class="close-btn" (click)="closeSegmentModal()">✕</button>
      </div>
      <div class="modal-body">
        <div class="form-section">
          <h4>段列表</h4>
          <table *ngIf="segmentModalSegments.length > 0" class="segment-edit-table">
            <thead>
              <tr>
                <th>段名</th>
                <th>段长 (KB)</th>
                <th>操作</th>
              </tr>
            </thead>
            <tbody>
              <tr *ngFor="let seg of segmentModalSegments; let i = index">
                <td>{{ seg.segmentName }}</td>
                <td>{{ seg.segmentLength }}</td>
                <td>
                  <button class="btn btn-small btn-delete" (click)="removeSegmentRow(i)">删除</button>
                </td>
              </tr>
            </tbody>
          </table>
          <div *ngIf="segmentModalSegments.length === 0" class="empty-state">暂未添加段</div>
        </div>
        <div class="form-section add-segment-form">
          <h4>添加段</h4>
          <div class="add-row">
            <input
              type="text"
              [(ngModel)]="newSegmentName"
              placeholder="段名(如:代码段)"
              class="form-input"
            />
            <input
              type="number"
              min="1"
              max="128"
              [(ngModel)]="newSegmentLength"
              class="form-input length-input"
              placeholder="段长(KB)"
            />
            <button
              class="btn btn-primary"
              (click)="addSegmentRow()"
              [disabled]="segmentModalSegments.length >= 8"
            >
              + 添加
            </button>
          </div>
          <p class="form-hint">段长范围: 1-128KB, 最多8段</p>
        </div>
      </div>
      <div class="modal-footer">
        <button class="btn btn-secondary" (click)="closeSegmentModal()">取消</button>
        <button class="btn btn-primary" (click)="saveSegmentModal()" [disabled]="segmentModalSegments.length === 0">分配</button>
      </div>
    </div>
  </div>
</div>
